# Frontend Style Guide — Sem Parar (Zustand-only + Hook Component Pattern)

Welcome to the **Sem Parar Frontend Style Guide**.  
This version consolidates: **Zustand as the only state manager**, **Hook Component pattern** for Screens and Atomic components, **services architecture (SOLID)**, and an **cache pattern**.

> Sit down, have a cup of coffee and read this calmly. ☕

---

## :pushpin: Table of Contents

- [Introduction](#introduction)
- [Components & Screens — Hook Component Pattern](#components--screens--hook-component-pattern)
- [Atomic Components — Hook Component Pattern](#atomic-components--hook-component-pattern)
- [Project Organization](#project-organization)
- [Services Architecture](#services-architecture)
- [State Management (Zustand-only)](#state-management-zustand-only)
- [Routes Naming](#routes-naming)
- [Folder Naming Rules](#folder-naming-rules)
- [Code Standards](#code-standards)
- [Styles Patterns](#styles-patterns)
- [Cache Pattern](#cache-pattern)
- [Checklist](#checklist)

---

## Introduction

The goal of this guide is to ensure **consistency, testability and scalability** across our frontend projects.

Key decisions:

- **Zustand** is the **exclusive** global/shared state manager.
- UI follows the **Hook Component** pattern (logic hook + dumb view).
- Domain logic lives in **`/services`** with **SOLID** layering.
- Cache is **typed and reusable**.

---

## Components & Screens — Hook Component Pattern

Each screen is split into a logic hook and a render-only component.

```
screens/Home/
├── index.ts        # logic: export useHomeScreen()
├── view.tsx        # render: export default HomeScreen
└── Models/
    └── index.d.ts    # types (Props, State, Handlers, Return)
```

**Models/index.d.ts**

```ts
export interface HomeParams {
  welcome?: string;
}
export interface HomeState {
  greeting: string;
  isLoading: boolean;
}
export interface HomeHandlers {
  onPressCTA: () => void;
}
export type UseHomeReturn = HomeState & HomeHandlers;
```

**index.ts (logic hook)**

```ts
import { useCallback, useMemo, useState, useEffect } from 'react';
import type { HomeParams, UseHomeReturn } from './Models';
import { useUserStore } from '@/services/user/store'; // Zustand slice example

export function useHomeScreen(params?: HomeParams): UseHomeReturn {
  const name = useUserStore(s => s.name);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    const t = setTimeout(() => setIsLoading(false), 300);
    return () => clearTimeout(t);
  }, []);

  const greeting = useMemo(
    () => params?.welcome ?? `Hello, ${name || 'guest'}!`,
    [
      params?.welcome,
      name,
    ],
  );

  const onPressCTA = useCallback(() => {
    // Call services, analytics, navigation, etc.
  }, []);

  return {
    greeting,
    isLoading,
    onPressCTA,
  };
}
```

**view.tsx (render)**

```tsx
import React from 'react';
import { View } from 'react-native';
import { Text, Button } from '@semparar/design-system-app';
import { useHomeScreen } from './index';
import type { HomeParams } from './Models';

type Props = HomeParams;

export default function HomeScreen(props: Props) {
  const { greeting, isLoading, onPressCTA } = useHomeScreen(props);

  if (isLoading) {
    return (
      <View>
        <Text>Loading...</Text>
      </View>
    );
  }

  return (
    <View>
      <Text>{greeting}</Text>
      <Button onPress={onPressCTA} text="Continue" />
    </View>
  );
}
```

---

## Atomic Components — Hook Component Pattern

```
atomic/atoms/Button/
├── index.ts        # logic: export useButton()
├── view.tsx        # render: export default Button
└── Models/
    └── index.d.ts
```

**Models/index.d.ts**

```ts
export interface ButtonProps {
  text: string;
  disabled?: boolean;
  onPress?: () => void;
}
export interface ButtonState {
  pressed: boolean;
}
export interface ButtonHandlers {
  handlePress: () => void;
}
export type UseButtonReturn = ButtonState & ButtonHandlers;
```

**index.ts (logic hook)**

```ts
import { useCallback, useState } from 'react';
import type { ButtonProps, UseButtonReturn } from './Models';

export function useButton(props: ButtonProps): UseButtonReturn {
  const [pressed, setPressed] = useState(false);

  const handlePress = useCallback(() => {
    setPressed(true);
    props.onPress?.();
    setTimeout(() => setPressed(false), 150);
  }, [props.onPress]);

  return {
    pressed,
    handlePress,
  };
}
```

**view.tsx (render)**

```tsx
import React from 'react';
import { Pressable, View } from 'react-native';
import { Text } from '@semparar/design-system-app';
import { useButton } from './index';
import type { ButtonProps } from './Models';

export default function Button(props: ButtonProps) {
  const { pressed, handlePress } = useButton(props);

  return (
    <Pressable disabled={props.disabled} onPress={handlePress}>
      <View>
        <Text>
          {props.text}
          {pressed ? ' •' : ''}
        </Text>
      </View>
    </Pressable>
  );
}
```

---

## Project Organization

```
src/
├── @types/            # Global TS types
├── assets/            # Images, fonts, icons
├── atomic/            # UI components (Hook Component pattern)
│   ├── atoms/
│   ├── molecules/
│   └── organisms/
├── modules/           # Microfrontends shared and native modules
├── screens/           # Page-level (Hook Component pattern)
├── services/          # Domain logic (SOLID layout)
│   ├── api/           # HTTP layer (Axios/Fetch)
│   ├── class/         # Class with logical requests
│   ├── hooks/         # Specific service hooks
│   ├── repository/    # Data abstraction & mapping
│   ├── services/      # Business orchestration
│   ├── storage/       # Storage orchestration with cache or not
│   ├── store/         # Zustand slices (only)
│   ├── models/        # Domain types & contracts
│   ├── utils/         # Reusable service helps
│   └── index.ts       # Public exports
├── hooks/             # Cross-cutting React hooks
├── routes/            # Navigation config
├── settings/          # Env & global config (axios, etc.)
└── utils/             # General-purpose helpers
```

> UI **never** calls API directly. All effects & side effects live in the **logic hooks** (which call `/services`).

---

## Services Architecture

**Flow:** `UI → services → repository → api` and `UI → services → store (Zustand)`

- **api/**: request clients; no domain logic.
- **class/**: class with logical requests.
- **hooks/**: specific service hooks.
- **repository/**: maps transport to domain, aggregates sources.
- **services/**: orchestration and business rules.
- **storage/**: storage orchestration with cache or not.
- **store/**: Zustand slices (single source of app state).
- **models/**: types, DTOs, contracts.
- **utils/**: reusable service helpers.

Principles:

- Single responsibility per folder/file.
- No circular dependencies.
- Public APIs exported via `services/index.ts` per domain.

---

## State Management (Zustand-only)

- All global/shared state is **Zustand**.
- Slices live under `/services/<domain>/store/`.
- Use `persist` (with `createJSONStorage`) only when needed.
- Keep setters pure; side effects go in hooks or services.

**Slice example**

```ts
import type { StateCreator } from 'zustand';
import type { AuthActions, AuthState } from '../models/store';

export type AuthSlice = {
  auth: AuthState;
  authActions: AuthActions;
};

const initialAuth = {
  user: null,
  loading: false,
  error: undefined,
};

export const createAuthSlice: StateCreator<
  AuthSlice,
  [],
  [],
  AuthSlice
> = set => ({
  auth: initialAuth,
  authActions: {
    setLoading: v =>
      set(s => ({
        auth: {
          ...s.auth,
          isLoading: v,
        },
      })),
    setUser: v =>
      set(s => ({
        auth: {
          ...s.auth,
          user: v,
        },
      })),
    setError: v =>
      set(s => ({
        auth: {
          ...s.auth,
          error: v,
        },
      })),
    reset: () => set({ auth: initialAuth }),
  },
});
```

**Root Store**

- Applies to ALL Sem Parar frontend apps — including SuperApp.

```ts
import { create } from 'zustand';
import { devtools, persist, createJSONStorage } from 'zustand/middleware';
import { immer } from 'zustand/middleware/immer';

import {
  createUserSlice,
  type UserSlice,
} from '@semparar/mf-app-user/src/newArch/user';
import { createAuthSlice, type AuthSlice } from '@semparar/mf-app-yourmf';

import storage from '~/redux/store/storage';

/** Add your slice Type */
export type RootStore = UserSlice & AuthSlice;

export const useRootStore = create<RootStore>()(
  devtools(
    persist(
      immer((...a) => ({
        ...createUserSlice(...a),
        ...createAuthSlice(...a), // Add your slice here
      })),
      {
        name: 'root-storage',
        storage: createJSONStorage(() => storage),
        partialize: s => ({
          user: s.user,
          auth: s.auth, // Add your store data
        }),
        merge: (persisted, current) => ({
          ...current,
          ...(persisted as Partial<RootStore>),
        }),
      },
    ),
    { name: 'RootStore' },
  ),
);
```

- For Use on Class.

```ts
class Auth {
  private readonly setAuth;

  constructor () {
    this.setUser = useRootStore.getState().authActions.setUser;
  }

  function doSomething(data) {
    this.setUser({ ...data });
  }
}
```

- For Use on Component/Screen.
- UI never imports the store directly — uses selectors

```ts
const loading = useRootStore(s => s.user.isLoading);
const token = useRootStore(s => s.auth.token);
```

---

## Routes Naming

Standardize as **`Acronym + Route`**:

- ✅ `SPPayment` (Sem Parar Payment)
- ✅ `FTHPayment` (Fintech Payment)

---

## Folder Naming Rules

| Folder                              | Convention   | Examples                   |
| ----------------------------------- | ------------ | -------------------------- |
| `atomic`, `screens`, `routes`       | `PascalCase` | `HomeScreen`, `CarDetails` |
| `assets`, `hooks`, `services`, etc. | `camelCase`  | `useAuth`, `authService`   |

---

## Code Standards

**Language**: English only.  
**Naming**: `camelCase` (vars/functions), `PascalCase` (components/classes), `UPPER_SNAKE_CASE` (constants).

**Explanatory variables**

```js
const onlyNumbersRegex = /^\d+$/;
const getNumberValidation = message => value =>
  !onlyNumbersRegex.test(value) && message;
const isNumber = getNumberValidation('error message');
isNumber(1);
```

**Semantic constants**

```js
const DAY_IN_MILLISECONDS = 86400000;
setTimeout(doSomething, DAY_IN_MILLISECONDS);
```

**Library workarounds with link**

```js
// Refer to issue https://github.com/ngokevin/react-file-reader-input/issues/11#issuecomment-363484861
// eslint-disable-next-line no-param-reassign
event.target.value = '';
```

**JSDoc**

```js
/**
 * Truncates an event name to the max length.
 * @param {*} eventName
 * @param {*} maxLength
 */
```

**Hooks: multi-line deps & IIFE**

```ts
useEffect(() => {
  (async () => {
    await CustomMath.randomSum();
    setSum(42);
  })();
}, [setSum]);
```

**Extract conditions**

```ts
const hasSelectedOffer = !!(selectedProduct || selectedLeasingOffer);
if (!hasSelectedOffer && !individualOffer) return;
```

**Optional chaining**

```ts
const answers = formikForm?.values?.answers;
```

**JSX indentation**

```tsx
{
  !isEnd && <Button text="CTA" onPress={handleNavigate} />;
}
```

**Early returns**

```ts
if (!data) return null;
return <View />;
```

**Nullish coalescing**

```ts
return data ?? 0;
```

---

## Styles Patterns

- Do **not** use `StyleSheet` or `styled-components`.
- Use **@semparar/design-system-app** for components, tokens, and theming.

---

## Cache Pattern

Keep cache typed, serializable, and domain.

```ts
import storage from '~/redux/store/storage';

export interface CachedData<T> {
  timestamp: number;
  data: T;
}

export interface StorageContract<T> {
  get(): Promise<CachedData<T> | null>;
  save(data: T): Promise<void>;
  remove(): Promise<void>;
}

export class GenericStorage<T> implements StorageContract<T> {
  constructor(private readonly key: string) {}

  async get(): Promise<CachedData<T> | null> {
    const json = await storage.getItem(this.key);
    if (!json) return null;
    return JSON.parse(json) as CachedData<T>;
  }

  async save(data: T): Promise<void> {
    const payload: CachedData<T> = {
      timestamp: Date.now(),
      data,
    };
    await storage.setItem(this.key, JSON.stringify(payload));
  }

  async remove(): Promise<void> {
    await storage.removeItem(this.key);
  }
}
```

**Guidelines**

- One storage class per module/feature.
- Types/interfaces live in `Models/` where appropriate.
- Use `timestamp` for freshness/expiry strategies.
- Never persist secrets/PII outside secure storage.
- Keep payloads small and JSON-serializable.

---

## Checklist

- [ ] Screens/Components follow **Hook Component pattern** (`index.ts` hook + `view.tsx` render)
- [ ] Types live in **Models/**
- [ ] Only **Zustand** for global/shared state under **/services/<domain>/store/**
- [ ] UI never calls API directly (go through **/services**)
- [ ] Code standards and styles patterns applied
- [ ] Cache implemented via **GenericStorage** (when needed)
- [ ] Routes and folder naming conventions followed

---

Happy shipping! 🚀

Proposta: Server Driven UI (SDUI): Um Padrão para Telas Parametrizáveis
Status: Rascunho
Versão: 1.0


                              Resumo

   Esta proposta descreve uma forma de estruturar o conteúdo das
   telas parametrizáveis (vouchers, benefícios, resgates, etc)
   de forma padronizada para reduzir a necessidade de deploy quando
   há mudanças de texto, formatação ou ordem de elementos.

   A proposta é baseada em padrões utilizados por empresas como
   Airbnb, Nubank e DoorDash, adaptados para nossa realidade.


Índice

   1. Contexto
   2. Proposta
   3. Como Funciona
      3.1. Estrutura de Tela
      3.2. Componentes
      3.3. Conteúdo Rico
      3.4. Valores e Contexto
      3.5. Regras e Condicionais
   4. Exemplo: Tela de Voucher
   5. Implementação
   6. Referências


1. Contexto

   Muitas aplicações possuem telas parametrizáveis, funcionando como 
   templates, que recebem dados do backend, definidos conforme a 
   necessidade de cada template. Na prática, os valores são dinâmicos,
   mas a estrutura não. A cada nova necessidade de alteração simples de
   layout e formatação, como destacar um texto em negrito, um novo campo é
   adicionado no JSON de resposta do servidor e uma nova regra condicional
   (if) é adicionada no frontend, resultando em armazenamento de dados legados
   e no acúmulo de código morto.

2. Proposta: Padrão SDUI.

    É um padrão arquitetural no qual o backend define a lógica de exibição 
    dos dados, indo além da definição de parâmetros textuais.

    Empresas que usam esse padrão:

        - Nubank: 70% das novas telas usam esse formato
        - Airbnb: Busca, listagens e checkout
        - DoorDash: Reduziu tempo de mudanças de semanas para horas

3. Como Funciona

3.1. Estrutura de Tela

     Uma tela é composta por:

     {
       "screen": {
         "id": "voucher_form",
         "context": { ... },      // dados para usar nos componentes
         "header": { ... },       // cabeçalho
         "body": [ ... ],         // array de componentes
         "footer": { ... }        // rodapé (botão de ação)
       }
     }

     O body é um array. A ordem do array é a ordem na tela.

3.2. Componentes

     Cada componente tem um tipo e propriedades:

     { "type": "heading", "props": { "text": "Título" } }
     { "type": "input", "props": { "label": "Valor em pontos" } }
     { "type": "button", "props": { "label": "Continuar" } }

     O app tem um registro de componentes:

     const Componentes = {
       'heading': HeadingComponent,
       'input': InputComponent,
       'button': ButtonComponent,
       'balance': BalanceComponent,
       // ...
     };

     Quando recebe o JSON, renderiza cada item do array usando
     o componente correspondente ao tipo.

     Tipos que já temos no Design System podem ser mapeados
     diretamente. Não precisa criar componentes novos.

3.3. Conteúdo Rico

     Para textos que precisam de formatação inline (negrito,
     links, ícones), usamos uma estrutura de "nodes":

     {
       "type": "rich_text",
       "children": [
         { "type": "text", "value": "Confira os " },
         { "type": "text", "value": "termos", "bold": true },
         { "type": "text", "value": " ou " },
         { "type": "link", "text": "fale conosco", "to": "app://suporte" }
       ]
     }

     Por que não markdown?

     Se usarmos [texto](url) para links e depois precisarmos
     adicionar tracking ou confirmação, temos que refatorar o
     parser.

     Com nodes, é só adicionar uma propriedade:

     {
       "type": "link",
       "text": "fale conosco",
       "to": "app://suporte",
       "trackEvent": "suporte_click"    // adicionado depois
     }

3.4. Valores e Contexto


     O Backend envia os valores no campo context:
     {
       "context": {
         "balance": {
           "points": 25720,
           "value": 7716.00
         }
       }
     }


     Para textos que dependem do contexto, usamos interpolação:

     { "type": "heading", "props": { "text": "Voucher para {{product.name}}" } }

     O app substitui {{product.name}} pelo valor do contexto.

3.5. Regras e Condicionais

     Para controlar visibilidade e habilitação, usamos regras
     simples baseadas em JSON Logic:

     Botão habilitado só quando valor > 0:

     {
       "type": "button",
       "props": {
         "label": "Continuar",
         "enabled": {
           "rule": { ">": [{ "var": "form.points" }, 0] }
         }
       }
     }

     Os operadores suportados são básicos:
     - var (acesso a dados)
     - ==, !=, >, <, >=, <= (comparação)
     - and, or, ! (lógica)

     Não tem loops, não tem eval, não tem risco.

     Validação de inputs segue o mesmo padrão:

     {
       "type": "input",
       "props": {
         "id": "points",
         "validation": {
           "rules": [
             {
               "rule": { ">": [{ "var": "value" }, 0] },
               "message": "Informe um valor maior que zero"
             }
           ]
         }
       }
     }

5. Exemplo: Tela de Voucher

   Estrutura completa para a tela de voucher:

   {
     "screen": {
       "id": "voucher_form",
       "context": {
         "product": {
           "key": "abastecimento",
           "name": "Abastecimento"
         },
         "balance": {
           "points": 25720,
           "pointsFormatted": "25.720",
           "valueFormatted": "R$ 7.716,00"
         }
       },
       "header": {
         "type": "nav_header",
         "props": {
           "title": "Voucher para {{product.name}}",
           "showBack": true
         }
       },
       "body": [
         {
           "type": "heading",
           "props": { "text": "Defina o desconto para seu {{product.key}}" }
         },
         {
           "type": "balance_display",
           "props": {
             "label": "Pontos disponíveis",
             "points": "{{balance.pointsFormatted}}",
             "value": "{{balance.valueFormatted}}"
           }
         },
         {
           "type": "points_input",
           "props": {
             "id": "points",
             "label": "Valor em pontos",
             "type": "numeric"
           }
         },
         {
           "type": "points_input",
           "props": {
             "id": "reais",
             "label": "Valor em reais",
             "type": "currency"
           }
         },
         {
           "type": "link",
           "props": {
             "text": "Exibir regras de uso",
             "to": "app://voucher/rules"
           }
         }
       ],
       "footer": {
         "type": "button",
         "props": {
           "label": "Continuar",
           "style": "primary",
           "enabled": {
             "rule": { ">": [{ "var": "form.points" }, 0] }
           }
         }
       }
     }
   }

   O mesmo código renderiza Abastecimento, Estacionamento,
   Seguro Auto e IPVA. Mudando apenas o context, não o app.


6. Implementação

   6.1. O que precisa ser feito

        - Registro de componentes (mapeamento tipo ‣ componente)
        - Renderizador que itera o array e renderiza cada tipo
        - Parser de interpolação (substituir {{var}})
        - Avaliador de regras (subset de JSON Logic)

   6.2. O que não muda

        - Design System continua o mesmo
        - Componentes existentes são reutilizados
        - Telas atuais continuam funcionando
        - Backend continua sendo Lambda que recebe/devolve JSON

   6.3. Escopo inicial

        Implementar na tela de Voucher (SPMAIS-34018) que já está
        com feature toggle. É o cenário ideal:

        - Feature nova, sem legado
        - 4 variações do mesmo fluxo
        - Retrabalho previsível (produto vai pedir ajustes)

   6.4. Validação

        O JSON pode ser validado antes de salvar no backend e
        antes de renderizar no app. Componentes desconhecidos
        usam fallback. Regras inválidas retornam false.

7. Referências

   [AIRBNB]    "A Deep Dive into Airbnb's Server-Driven UI System"
               https://medium.com/airbnb-engineering/a-deep-dive-into-airbnbs-server-driven-ui-system-842244c5f5

   [NUBANK]    "Backend Driven Content at Nubank"
               https://building.nubank.com/server-driven-ui-framework-at-nubank/

   [JSONLOGIC] JSON Logic - Regras em JSON
               https://jsonlogic.com/

import React, { useState, useRef } from 'react';
import { View, ScrollView } from 'react-native';
import {
  Text,
  Button,
  Box,
  InputBox,
  Alert,
  Icon,
  ListTextIcon,
  SeparatorHorizontal,
  BackDropBottom,
  Loading,
} from '@semparar/design-system-app';
import type { Meta, StoryObj } from 'storybook/internal/types';

function StatusBadge({ status }: { status: 'ok' | 'fail' | 'warn' }) {
  const colors = { ok: '#22c55e', fail: '#ef4444', warn: '#f59e0b' };
  const labels = { ok: 'RENDERS', fail: 'FAILS', warn: 'PARTIAL' };
  return (
    <View
      style={{
        backgroundColor: colors[status],
        paddingHorizontal: 8,
        paddingVertical: 2,
        borderRadius: 4,
        alignSelf: 'flex-start',
        marginBottom: 8,
      }}
    >
      <Text type="bodySM" color="INTENSE_COLOR_01">
        {labels[status]}
      </Text>
    </View>
  );
}

function Section({
  title,
  children,
}: {
  title: string;
  children: React.ReactNode;
}) {
  return (
    <View style={{ marginBottom: 32 }}>
      <Text type="subtitleXXL" mb="smaller">
        {title}
      </Text>
      <Box
        pd="squishSmall"
        bgColor="LIGHT_BASE_02"
        br="sm"
        bw="thin"
        borderColor="BRAND_COMPLEMENT_02"
      >
        {children}
      </Box>
    </View>
  );
}

function TextValidation() {
  return (
    <Section title="1. Text">
      <StatusBadge status="ok" />
      <Text type="headingMDL" mb="nano">
        headingMDL — Form titles
      </Text>
      <Text type="subtitleXXL" mb="nano">
        subtitleXXL — Section headings
      </Text>
      <Text type="bodyMD" mb="nano">
        bodyMD — Body text
      </Text>
      <Text type="paragraphMD" mb="nano">
        paragraphMD — Descriptions
      </Text>
      <Text type="bodySM" mb="nano" color="INTENSE_COLOR_03">
        bodySM + color — Secondary text
      </Text>
      <Text
        type="bodyMD"
        color="PRYMARY_BASE_02"
        underline
        onPress={() => {}}
      >
        Pressable + underline — Link style
      </Text>
    </Section>
  );
}

