import { chromium } from 'playwright';
import { mkdirSync } from 'fs';

const STORYBOOK_URL = process.env.STORYBOOK_URL || 'http://localhost:6006';
const OUTPUT_DIR = '.storybook/screenshots';

const STORIES = [
  {
    id: 'validation-ds-components--all-components',
    name: 'ds-validation-all-components',
  },
  {
    id: 'smoketest-ds-components--default',
    name: 'smoke-test',
  },
];

async function main() {
  mkdirSync(OUTPUT_DIR, { recursive: true });

  const browser = await chromium.launch();
  const context = await browser.newContext({
    viewport: { width: 480, height: 900 },
  });
  const page = await context.newPage();

  for (const story of STORIES) {
    const url = `${STORYBOOK_URL}/iframe.html?id=${story.id}&viewMode=story`;
    console.log(`Capturing: ${story.name} → ${url}`);

    await page.goto(url, { waitUntil: 'domcontentloaded', timeout: 30000 });
    await page.waitForTimeout(8000);

    await page.screenshot({
      path: `${OUTPUT_DIR}/${story.name}.png`,
      fullPage: true,
    });
    console.log(`  Saved: ${OUTPUT_DIR}/${story.name}.png`);
  }

  await browser.close();
  console.log('Done!');
}

main().catch(err => {
  console.error(err);
  process.exit(1);
});

